	&lt;li data-end=&quot;680&quot; data-start=&quot;574&quot;&gt;
	&lt;p data-end=&quot;680&quot; data-start=&quot;576&quot;&gt;Key themes include &lt;strong data-end=&quot;613&quot; data-start=&quot;595&quot;&gt;sustainability&lt;/strong&gt;, &lt;strong data-end=&quot;654&quot; data-start=&quot;615&quot;&gt;women and minority entrepreneurship&lt;/strong&gt;, and &lt;strong data-end=&quot;679&quot; data-start=&quot;660&quot;&gt;tech innovation&lt;/strong&gt;.&lt;/p&gt;
